module traffic_light
(
    input rst_n,
    input clk,
    input pass_request,
    output [7:0] clock,
    output red
);
parameter idle = 2'b00;
parameter s1_red = 2'b01;
parameter s2_yellow = 2'b10;
parameter s3_green = 2'b11;
reg [1:0] state, next_state;
reg [7:0] cnt, next_cnt;
reg p_red, p_yellow, p_green;
always @(*) begin
    case (state)
        idle: begin
            next_state = s1_red;
        end
        s1_red: begin
            if (cnt == 5) begin
                next_state = s3_green;
            end
            else begin
                next_state = s1_red;
            end
        end
        s2_yellow: begin
            if (cnt == 5) begin
                next_state = s1_red;
            end
            else begin
                next_state = s2_yellow;
            end
        end
        s3_green: begin
            if (cnt == 5) begin
                next_state = s2_yellow;
            end
            else begin
                next_state = s3_green;
            end
        end
        default: begin
            next_state = idle;
        end
    endcase
end
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        state <= idle;
    end
    else begin
        state <= next_state;
    end
end
always @(*) begin
    if (!rst_n) begin
        next_cnt = 10;
    end
    else if (pass_request && green) begin
        next_cnt = 10;
    end
    else if (!green && p_green) begin
        next_cnt = 60;
    end
    else if (!yellow && p_yellow) begin
        next_cnt = 5;
    end
    else if (!red && p_red) begin
        next_cnt = 10;
    end
    else begin
        next_cnt = cnt - 1;
    end
end
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        cnt <= 10;
    end
    else begin
        cnt <= next_cnt;
    end
end
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        p_red <= 0;
        p_yellow <= 0;
        p_green <= 0;
    end
    else begin
        p_red <= red;
        p_yellow <= yellow;
        p_green <= green;
    end
end
assign clock = cnt;
endmodule
